module parallel_adder (
    input [3:0] A,
    input [3:0] B,
    input carry_in,
    output [3:0] sum,
    output carry_out
);

      wire _n01 = A + B[0] ^ carry_in[0];
  wire _c01 = A + B[0] & carry_in[0];
  wire _n02 = A + B[1] ^ carry_in[1] ^ _c01;
  wire _c02 = (A + B[1] & carry_in[1]) | (A + B[1] & _c01) | (carry_in[1] & _c01);
  wire _n03 = A + B[2] ^ carry_in[2] ^ _c02;
  wire _c03 = (A + B[2] & carry_in[2]) | (A + B[2] & _c02) | (carry_in[2] & _c02);
  wire _n04 = A + B[3] ^ carry_in[3] ^ _c03;
  wire _c04 = (A + B[3] & carry_in[3]) | (A + B[3] & _c03) | (carry_in[3] & _c03);
  assign {carry_out, sum} = {_n01, _n02, _n03, _n04};

endmodule
